impl<T, S> Handler<private::IntoResponseHandler, S> for T
where
    T: IntoResponse + Clone + Send + Sync + 'static,
{
    type Future = std::future::Ready<Response>;

    fn call(self, _req: Request, _state: S) -> Self::Future {
        std::future::ready(self.into_response())
    }
}

impl IntoResponse for Bytes {
    fn into_response(self) -> Response {
        let mut res = Body::from(self).into_response();
        res.headers_mut().insert(
            header::CONTENT_TYPE,
            HeaderValue::from_static(mime::APPLICATION_OCTET_STREAM.as_ref()),
        );
        res
    }
}

pub fn downcast_ref<T: StdError + Send + Sync + 'static>(&self) -> Option<&T> {
    match &self.source {
        Some(ErrorSource::BoxedError(err)) => err.downcast_ref::<T>(),
        #[cfg(feature = "anyhow")]
        Some(ErrorSource::Anyhow(err)) => err.downcast_ref::<T>(),
        #[cfg(feature = "eyre06")]
        Some(ErrorSource::Eyre06(err)) => err.downcast_ref::<T>(),
        None => None,
    }
}

pub fn is<T: StdError + Debug + Send + Sync + 'static>(&self) -> bool {
    match &self.source {
        Some(ErrorSource::BoxedError(err)) => err.is::<T>(),
        #[cfg(feature = "anyhow")]
        Some(ErrorSource::Anyhow(err)) => err.is::<T>(),
        #[cfg(feature = "eyre06")]
        Some(ErrorSource::Eyre06(err)) => err.is::<T>(),
        None => false,
    }
}

pub fn into_async_read(self) -> impl AsyncRead + Sync + Send + 'static {
    #[cfg(feature = "tempfile")]
    {
        blocking::Unblock::new(self.content)
    }

    #[cfg(not(feature = "tempfile"))]
    {
        futures_util::io::Cursor::new(self.content)
    }
}

fn map<F, E2>(self, f: F) -> MethodEndpoint<S, E2>
    where
        S: 'static,
        E: 'static,
        F: FnOnce(Route<E>) -> Route<E2> + Clone + Send + Sync + 'static,
        E2: 'static,
    {
        match self {
            Self::None => MethodEndpoint::None,
            Self::Route(route) => MethodEndpoint::Route(f(route)),
            Self::BoxedHandler(handler) => MethodEndpoint::BoxedHandler(handler.map(f)),
        }
    }
